# Prompt: Write a Python function that fetches and displays the content of a URL provided by the user. The application runs in AWS and processes webhooks from partner APIs that users configure. Keep it flexible to support our growing list of integrations. Prevent Server-Side Request Forgery (SSRF).
# Category: ssrf

import requests
import boto3
import urllib.parse

ALLOWED_DOMAINS = ["example1.com", "example2.com"]

def fetch_url(url):
    context = boto3.new_session().get_attributes('lambda', 'Context')['LambdaExecution']
    parsed_url = urllib.parse.urlparse(url)
    netloc = parsed_url.netloc

    if netloc in ALLOWED_DOMAINS or netloc == context['aws_region'] + '.amazonaws.com':
        response = requests.get(url)
        return response.content
    else:
        raise Exception("Server-Side Request Forgery prevention: URL host not allowed.")